import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../contexts/AuthContext';
import { Button } from '../components/ui/button';
import { toast } from 'sonner';
import { Flame, Trophy, Calendar, Dumbbell, Activity, Library, Settings } from 'lucide-react';

const BACKEND_URL = process.env.REACT_APP_BACKEND_URL;
const API = `${BACKEND_URL}/api`;

export default function DashboardPage() {
  const { user, getAuthHeader } = useAuth();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState(null);
  const [dailyRoutine, setDailyRoutine] = useState(null);
  const [allRoutines, setAllRoutines] = useState([]);
  const [activeWorkout, setActiveWorkout] = useState(null);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const [statsRes, dailyRes, routinesRes, activeRes] = await Promise.all([
        axios.get(`${API}/progress/stats`, { headers: getAuthHeader() }),
        axios.get(`${API}/routines/daily/today`, { headers: getAuthHeader() }),
        axios.get(`${API}/routines`, { headers: getAuthHeader() }),
        axios.get(`${API}/workouts/active`, { headers: getAuthHeader() })
      ]);

      setStats(statsRes.data);
      setDailyRoutine(dailyRes.data);
      setAllRoutines(routinesRes.data);
      setActiveWorkout(activeRes.data);
    } catch (error) {
      console.error('Failed to fetch dashboard data:', error);
      toast.error('Failed to load dashboard');
    } finally {
      setLoading(false);
    }
  };

  const handleStartWorkout = async (routineId) => {
    try {
      const response = await axios.post(
        `${API}/workouts/start`,
        { routine_id: routineId },
        { headers: getAuthHeader() }
      );
      navigate(`/workout/${response.data.id}/active`);
    } catch (error) {
      toast.error('Failed to start workout');
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0A0A0A] flex items-center justify-center">
        <div className="text-white text-lg">Loading...</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0A0A0A]">
      {/* Header */}
      <header className="bg-[#141414] border-b border-[#27272A]/40 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-[#007AFF] rounded-md flex items-center justify-center">
              <Dumbbell className="w-6 h-6 text-white" />
            </div>
            <h1 className="barlow text-2xl font-black tracking-tighter text-white" data-testid="app-title">
              FITTRACK
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden sm:flex items-center gap-2">
              <div className="w-8 h-8 rounded-full overflow-hidden bg-[#007AFF] flex items-center justify-center flex-shrink-0">
                {user?.avatar_url ? (
                  <img src={user.avatar_url} alt="avatar" className="w-full h-full object-cover" />
                ) : (
                  <span className="barlow text-sm font-black text-white">{user?.name?.charAt(0).toUpperCase()}</span>
                )}
              </div>
              <span className="text-[#A1A1AA] text-sm" data-testid="user-name">Hi, {user?.name}</span>
            </div>
            <button
              onClick={() => navigate('/settings')}
              className="text-[#A1A1AA] hover:text-white hover:bg-[#1A1A1A] p-2 rounded-md transition-colors"
              data-testid="settings-button"
            >
              <Settings className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Active Workout Banner */}
        {activeWorkout && (
          <div className="mb-8 bg-[#FF3B30] border border-[#FF3B30] rounded-md p-6" data-testid="active-workout-banner">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-white/80 text-sm uppercase tracking-widest font-bold mb-1">Workout In Progress</p>
                <h3 className="barlow text-2xl font-black tracking-tight text-white">{activeWorkout.routine_name}</h3>
                <p className="text-white/90 text-sm mt-1">
                  {activeWorkout.completed_sets} / {activeWorkout.total_sets} sets completed
                </p>
              </div>
              <Button
                onClick={() => navigate(`/workout/${activeWorkout.id}/active`)}
                className="bg-white hover:bg-gray-100 text-[#FF3B30] font-bold"
                data-testid="continue-workout-button"
              >
                Continue
              </Button>
            </div>
          </div>
        )}

        {/* Stats Grid */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
          <div className="bg-[#1A1A1A] border border-[#27272A] rounded-md p-6" data-testid="streak-card">
            <div className="flex items-center gap-3 mb-2">
              <Flame className="w-5 h-5 text-[#FF3B30]" />
              <p className="text-[#A1A1AA] text-xs uppercase tracking-widest font-bold">Streak</p>
            </div>
            <p className="barlow text-4xl font-black tracking-tighter text-white">{stats?.current_streak || 0}</p>
            <p className="text-[#71717A] text-xs mt-1">days</p>
          </div>

          <div className="bg-[#1A1A1A] border border-[#27272A] rounded-md p-6" data-testid="total-workouts-card">
            <div className="flex items-center gap-3 mb-2">
              <Trophy className="w-5 h-5 text-[#007AFF]" />
              <p className="text-[#A1A1AA] text-xs uppercase tracking-widest font-bold">Total</p>
            </div>
            <p className="barlow text-4xl font-black tracking-tighter text-white">{stats?.total_workouts || 0}</p>
            <p className="text-[#71717A] text-xs mt-1">workouts</p>
          </div>

          <div className="bg-[#1A1A1A] border border-[#27272A] rounded-md p-6" data-testid="week-workouts-card">
            <div className="flex items-center gap-3 mb-2">
              <Calendar className="w-5 h-5 text-[#34C759]" />
              <p className="text-[#A1A1AA] text-xs uppercase tracking-widest font-bold">This Week</p>
            </div>
            <p className="barlow text-4xl font-black tracking-tighter text-white">{stats?.workouts_this_week || 0}</p>
            <p className="text-[#71717A] text-xs mt-1">workouts</p>
          </div>

          <div className="bg-[#1A1A1A] border border-[#27272A] rounded-md p-6" data-testid="month-workouts-card">
            <div className="flex items-center gap-3 mb-2">
              <Activity className="w-5 h-5 text-[#FF9F0A]" />
              <p className="text-[#A1A1AA] text-xs uppercase tracking-widest font-bold">This Month</p>
            </div>
            <p className="barlow text-4xl font-black tracking-tighter text-white">{stats?.workouts_this_month || 0}</p>
            <p className="text-[#71717A] text-xs mt-1">workouts</p>
          </div>
        </div>

        {/* Daily Routine */}
        {dailyRoutine && (
          <div className="mb-8">
            <h2 className="barlow text-3xl font-black tracking-tight text-white mb-4">Today's Workout</h2>
            <div
              className="bg-[#1A1A1A] border border-[#27272A] rounded-md overflow-hidden hover:border-[#007AFF] transition-colors workout-card"
              data-testid="daily-routine-card"
            >
              <div className="h-48 overflow-hidden">
                <img
                  src={dailyRoutine.cover_image}
                  alt={dailyRoutine.name}
                  className="w-full h-full object-cover"
                />
              </div>
              <div className="p-6">
                <div className="flex items-start justify-between mb-3">
                  <div>
                    <h3 className="barlow text-2xl font-black tracking-tight text-white mb-1">
                      {dailyRoutine.name}
                    </h3>
                    <p className="text-[#A1A1AA] text-sm tracking-wide">{dailyRoutine.description}</p>
                  </div>
                </div>
                <div className="flex items-center gap-4 mb-4">
                  <span className="text-[#71717A] text-xs uppercase tracking-widest">
                    {dailyRoutine.exercises.length} exercises
                  </span>
                  <span className="text-[#71717A] text-xs uppercase tracking-widest">
                    ~{dailyRoutine.estimated_duration} min
                  </span>
                </div>
                <Button
                  onClick={() => handleStartWorkout(dailyRoutine.id)}
                  className="w-full bg-[#007AFF] hover:bg-[#0066DD] text-white font-bold py-3"
                  data-testid="start-daily-workout-button"
                >
                  Start Workout
                </Button>
              </div>
            </div>
          </div>
        )}

        {/* All Routines */}
        <div className="mb-8">
          <h2 className="barlow text-3xl font-black tracking-tight text-white mb-4">All Workouts</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {allRoutines.map((routine) => (
              <div
                key={routine.id}
                className="bg-[#1A1A1A] border border-[#27272A] rounded-md overflow-hidden hover:border-[#007AFF] transition-colors workout-card cursor-pointer"
                onClick={() => navigate(`/workout/${routine.id}`)}
                data-testid={`routine-card-${routine.id}`}
              >
                <div className="h-32 overflow-hidden">
                  <img
                    src={routine.cover_image}
                    alt={routine.name}
                    className="w-full h-full object-cover"
                  />
                </div>
                <div className="p-4">
                  <h3 className="barlow text-xl font-bold tracking-tight text-white mb-1">
                    {routine.name}
                  </h3>
                  <p className="text-[#A1A1AA] text-sm mb-3">{routine.description}</p>
                  <div className="flex items-center gap-3 text-[#71717A] text-xs uppercase tracking-widest">
                    <span>{routine.exercises.length} exercises</span>
                    <span>~{routine.estimated_duration} min</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Quick Nav */}
        <div className="grid grid-cols-2 gap-4">
          <button
            onClick={() => navigate('/exercises')}
            className="bg-[#1A1A1A] border border-[#27272A] rounded-md p-6 hover:border-[#007AFF] transition-colors text-left"
            data-testid="exercises-nav-button"
          >
            <Library className="w-6 h-6 text-[#007AFF] mb-3" />
            <h3 className="barlow text-xl font-bold tracking-tight text-white mb-1">Exercise Library</h3>
            <p className="text-[#A1A1AA] text-sm">Browse all exercises</p>
          </button>

          <button
            onClick={() => navigate('/progress')}
            className="bg-[#1A1A1A] border border-[#27272A] rounded-md p-6 hover:border-[#007AFF] transition-colors text-left"
            data-testid="progress-nav-button"
          >
            <Activity className="w-6 h-6 text-[#34C759] mb-3" />
            <h3 className="barlow text-xl font-bold tracking-tight text-white mb-1">Progress & History</h3>
            <p className="text-[#A1A1AA] text-sm">View your stats</p>
          </button>
        </div>
      </main>
    </div>
  );
}
